        holo { Vector(0, 12, 15), Angle(270, 90, 0), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(0, 12, -15), Angle(90, 90, 180), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(15, 12, 0), Angle(0, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(-15, 12, 0), Angle(180, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(9, 12, 9), Angle(315, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(-9, 12, 9), Angle(225, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(-9, 12, -9), Angle(135, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
        holo { Vector(9, 12, -9), Angle(45, 0, 90), "models/props_combine/breenlight.mdl", Vector(1, 1.6, 4), color = mainColor, material = metalMat },
    })
    :add("forearm", "prongs", part {
       rig ( Vector(0, 80, 0), Angle() ),
       prongsFun ()
    })
    :addPoseParameter("rotation_multiplier")
    :addSequence("idle", 0, function(ent, layer)
        local tube = ent:getBoneEntity(ent:lookupBone("tube"))
        local prongs = ent:getBoneEntity(ent:lookupBone("prongs"))
        local shoulder = ent:getBoneEntity(ent:lookupBone("shoulder"))
        local forearm = ent:getBoneEntity(ent:lookupBone("forearm"))
        local _, shoulderAng = shoulder:getPropertyForLayer(layer)
        local _, forearmAng = forearm:getPropertyForLayer(layer)

        shoulder:setLocalAnglesLayer(layer + 1, tween.blenderRotation(19.5255, 35.631, -58.67))
        forearm:setLocalAnglesLayer(layer + 1, tween.blenderRotation(-180.605, -63.6716, 164.196))

        return tween.new {
            param { 0, 4, shoulder, circleProperty(2, nil, layer), nil, 1},
            param { 0, 2, shoulder, shoulderAng, Angle(-5, 0, 2), Angle(), math.easeInOutSine },
            param { 2, 4, shoulder, shoulderAng, Angle(), Angle(-5, 0, 2), math.easeInOutSine },

            param { 0, 2, forearm, forearmAng, Angle(0, 5, 0), Angle(), math.easeInOutSine },
            param { 2, 4, forearm, forearmAng, Angle(), Angle(0, 5, 0), math.easeInOutSine },
            function(process)
                local delta = timer.frametime()
                local poseParameter = ent:getPoseParameter("rotation_multiplier")
                tube:setLocalAngles(tube:getLocalAngles() + Angle(400 * delta * poseParameter, 0, 0))
                prongs:setLocalAngles(prongs:getLocalAngles() + Angle(200 * delta * poseParameter, 0, 0))
                if process > 4 then return true end
            end
        }
    end)
    :addSequence("startLaser", 2, function(ent, layer)
        local shoulder = ent:getBoneEntity(ent:lookupBone("shoulder"))
        local forearm = ent:getBoneEntity(ent:lookupBone("forearm"))

        local _, shoulderAng = shoulder:getPropertyForLayer(layer)
        local _, forearmAng = forearm:getPropertyForLayer(layer)

        return tween.new {
            param { 0, 0.5, shoulder, shoulderAng, nil, Angle(-30, -90, 0), math.easeInOutQuint },
            param { 0, 0.5, forearm, forearmAng, nil, Angle(), math.easeInOutQuint },
            function(process)
                local eased = math.easeOutQuart(process / 2) * 5
                ent:setPoseParameter("rotation_multiplier", 1 + eased)
                if process > 2 then return true end
            end
        }
    end)
    :addSequence("laser", 0, function(ent)
        local shoulder = ent:getBoneEntity(ent:lookupBone("shoulder"))

        return function(process)
            local fraction = math.min(process / 0.1, 1)
            shoulder:setLocalPos(Vector(math.sin(fraction * math.pi * 2) * 2, math.rand(-1, 1), math.rand(-1, 1)))
            if fraction == 1 then return true end
        end
    end)
    :addSequence("stopLaser", 1, function(ent, layer)
        local shoulder = ent:getBoneEntity(ent:lookupBone("shoulder"))
        local forearm = ent:getBoneEntity(ent:lookupBone("forearm"))

        local _, shoulderAng = shoulder:getPropertyForLayer(layer)
        local _, forearmAng = forearm:getPropertyForLayer(layer)

        return tween.new {
            param { 0, 1, shoulder, shoulderAng, nil, tween.blenderRotation(19.5255, 35.631, -58.67), math.easeInOutQuint },
            param { 0, 1, forearm, forearmAng, nil, tween.blenderRotation(-180.605, -63.6716, 164.196), math.easeInOutQuint },
            function(process)
                local eased = math.easeInSine(1 - process) * 5
                ent:setPoseParameter("rotation_multiplier", 1 + eased)
                if process > 1 then return true end
            end
        }
    end)


